import axios from 'axios';
import { WEATHER_API } from '../utils/constants';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Location from 'expo-location';

const STORAGE_KEYS = {
  USER_LOCATION: 'climate_closet_user_location',
  LOCATION_TIMESTAMP: 'climate_closet_location_timestamp',
};

const LOCATION_CACHE_DURATION = 1000 * 60 * 10; // 10 minutes

export interface LocationSuggestion {
  name: string;
  state?: string;
  country: string;
  lat: number;
  lon: number;
  distance?: number;
}

interface UserLocation {
  latitude: number;
  longitude: number;
  timestamp: number;
}

class LocationError extends Error {
  constructor(message: string, public code?: string) {
    super(message);
    this.name = 'LocationError';
  }
}

/**
 * Calculate distance between two points using the Haversine formula
 */
const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number): number => {
  const R = 6371; // Earth's radius in km
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLon = ((lon2 - lon1) * Math.PI) / 180;
  const a =
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos((lat1 * Math.PI) / 180) *
    Math.cos((lat2 * Math.PI) / 180) *
    Math.sin(dLon / 2) *
    Math.sin(dLon / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

/**
 * Get the user's current location, using cached value if available and recent
 */
export const getUserLocation = async (): Promise<UserLocation | null> => {
  try {
    // Check for cached location
    const cachedLocationJson = await AsyncStorage.getItem(STORAGE_KEYS.USER_LOCATION);
    const cachedTimestampStr = await AsyncStorage.getItem(STORAGE_KEYS.LOCATION_TIMESTAMP);

    if (cachedLocationJson && cachedTimestampStr) {
      const cachedLocation = JSON.parse(cachedLocationJson);
      const cachedTimestamp = parseInt(cachedTimestampStr, 10);

      // Use cached location if it's less than 10 minutes old
      if (Date.now() - cachedTimestamp < LOCATION_CACHE_DURATION) {
        return {
          ...cachedLocation,
          timestamp: cachedTimestamp,
        };
      }
    }

    // Get fresh location
    const { status } = await Location.requestForegroundPermissionsAsync();
    if (status !== 'granted') {
      throw new LocationError('Location permission denied', 'PERMISSION_DENIED');
    }

    const location = await Location.getCurrentPositionAsync({
      accuracy: Location.Accuracy.Balanced,
    });

    const userLocation = {
      latitude: location.coords.latitude,
      longitude: location.coords.longitude,
      timestamp: Date.now(),
    };

    // Cache the new location
    await AsyncStorage.setItem(STORAGE_KEYS.USER_LOCATION, JSON.stringify({
      latitude: userLocation.latitude,
      longitude: userLocation.longitude,
    }));
    await AsyncStorage.setItem(STORAGE_KEYS.LOCATION_TIMESTAMP, userLocation.timestamp.toString());

    return userLocation;
  } catch (error) {
    console.warn('Error getting user location:', error);
    return null;
  }
};

/**
 * Search for location suggestions using OpenWeatherMap's Geocoding API
 * Results are sorted by distance from user's location if available
 */
export const searchLocations = async (query: string, limit: number = 5): Promise<LocationSuggestion[]> => {
  if (!query.trim()) {
    return [];
  }

  try {
    const response = await axios.get(
      'https://api.openweathermap.org/geo/1.0/direct',
      {
        params: {
          q: query,
          limit: limit * 2, // Request more results to allow for better distance-based sorting
          appid: WEATHER_API.KEY
        }
      }
    );

    let suggestions = response.data.map((location: any) => ({
      name: location.name,
      state: location.state,
      country: location.country,
      lat: location.lat,
      lon: location.lon
    }));

    // Try to get user location for distance-based sorting
    const userLocation = await getUserLocation();

    if (userLocation) {
      // Calculate distances and sort
      suggestions = suggestions.map((suggestion: LocationSuggestion) => ({
        ...suggestion,
        distance: calculateDistance(
          userLocation.latitude,
          userLocation.longitude,
          suggestion.lat,
          suggestion.lon
        )
      })).sort((a: LocationSuggestion, b: LocationSuggestion) => (a.distance || 0) - (b.distance || 0));
    }

    // Return only the requested number of results
    return suggestions.slice(0, limit);
  } catch (error: any) {
    if (axios.isAxiosError(error)) {
      if (error.response?.status === 401) {
        throw new LocationError('Invalid API key. Please check your configuration.', 'INVALID_API_KEY');
      } else if (!error.response) {
        throw new LocationError('Network error. Please check your connection.', 'NETWORK_ERROR');
      }
    }
    throw new LocationError('Failed to fetch location suggestions. Please try again.', 'UNKNOWN_ERROR');
  }
};

/**
 * Format location for display and storage
 */
export const formatLocation = (location: LocationSuggestion): string => {
  const parts = [location.name];
  if (location.state) {
    parts.push(location.state);
  }
  parts.push(location.country);
  return parts.join(', ');
};

/**
 * Parse a formatted location string back into its components
 */
export const parseLocation = (formattedLocation: string): string[] => {
  return formattedLocation.split(',').map(part => part.trim());
};
